commit d495deda7ec672cabaf1fa48ceae4e798e49a275
Author: Albert Hazan <u2giants@users.noreply.github.com>
Date:   Thu Jun 18 14:06:57 2026 -0400

    make all dropdowns type-to-search

    DataTable inline cell-edit dropdown now has a search box (for lists >3),
    and FilterSelect is backed by the searchable Combobox. Long entity
    pickers already used Combobox; short enum Selects keep Radix's native
    typeahead — so every dropdown is now typeable.

    Co-Authored-By: Claude Sonnet 4.6 <noreply@anthropic.com>
    Claude-Session: https://claude.ai/code/session_01FUBkE8ebNdu5nnsVJDHXFq

diff --git a/src/components/app/FilterSelect.tsx b/src/components/app/FilterSelect.tsx
index 16a8684..8040448 100644
--- a/src/components/app/FilterSelect.tsx
+++ b/src/components/app/FilterSelect.tsx
@@ -1,12 +1,7 @@
-import {
-  Select,
-  SelectContent,
-  SelectItem,
-  SelectTrigger,
-  SelectValue,
-} from '@/components/ui/select'
+import { Combobox } from '@/components/app/Combobox'

 // A compact filter dropdown with an "all" sentinel. Value '' means no filter.
+// Backed by the searchable Combobox so any filter can be typed into.
 export function FilterSelect({
   value,
   onChange,
@@ -23,18 +18,14 @@ export function FilterSelect({
   className?: string
 }) {
   return (
-    <Select value={value || '__all__'} onValueChange={(v) => onChange(v === '__all__' ? '' : v)}>
-      <SelectTrigger size="sm" className={className}>
-        <SelectValue placeholder={placeholder} />
-      </SelectTrigger>
-      <SelectContent>
-        <SelectItem value="__all__">{allLabel}</SelectItem>
-        {options.map((o) => (
-          <SelectItem key={o.value} value={o.value}>
-            {o.label}
-          </SelectItem>
-        ))}
-      </SelectContent>
-    </Select>
+    <Combobox
+      value={value}
+      onChange={onChange}
+      options={options}
+      placeholder={placeholder ?? allLabel}
+      allowClear
+      clearLabel={allLabel}
+      className={className}
+    />
   )
 }

